import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { usuarioService } from '../services/api';

const AlterarSenhaPage: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [senhaAtual, setSenhaAtual] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [confirmarSenha, setConfirmarSenha] = useState('');
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState<{mensagem: string, tipo: 'success' | 'error'} | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (novaSenha.length < 6) {
      setFeedback({
        mensagem: 'A nova senha deve ter pelo menos 6 caracteres.',
        tipo: 'error'
      });
      return;
    }
    
    if (novaSenha !== confirmarSenha) {
      setFeedback({
        mensagem: 'As senhas não coincidem.',
        tipo: 'error'
      });
      return;
    }
    
    setLoading(true);
    
    try {
      await usuarioService.atualizarPerfil({
        senhaAtual,
        novaSenha
      });
      
      setFeedback({
        mensagem: 'Senha alterada com sucesso!',
        tipo: 'success'
      });
      setSenhaAtual('');
      setNovaSenha('');
      setConfirmarSenha('');
      
      // Redirecionar para perfil após alguns segundos
      setTimeout(() => {
        navigate('/perfil');
      }, 2000);
    } catch (err: any) {
      setFeedback({
        mensagem: err.response?.data?.erro || 'Erro ao alterar senha',
        tipo: 'error'
      });
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate('/perfil');
  };

  return (
    <div className="container mx-auto px-4 py-8">
      
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-cursor-text-primary">Alterar Senha</h1>
        <p className="text-cursor-text-secondary mt-1">
          Atualize sua senha de acesso
        </p>
      </div>
      
      <div className="bg-white rounded-lg shadow-cursor overflow-hidden max-w-md mx-auto">
        <div className="p-6">
          {feedback && (
            <div className={`p-4 mb-4 rounded-lg ${feedback.tipo === 'success' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
              {feedback.mensagem}
            </div>
          )}
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">
                Senha Atual*
              </label>
              <input
                type="password"
                className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                value={senhaAtual}
                onChange={e => setSenhaAtual(e.target.value)}
                placeholder="••••••••"
                required
              />
            </div>
            
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">
                Nova Senha*
              </label>
              <input
                type="password"
                className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                value={novaSenha}
                onChange={e => setNovaSenha(e.target.value)}
                placeholder="••••••••"
                required
                minLength={6}
              />
              <p className="text-xs text-cursor-text-tertiary mt-1">
                Mínimo de 6 caracteres
              </p>
            </div>
            
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">
                Confirmar Nova Senha*
              </label>
              <input
                type="password"
                className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                value={confirmarSenha}
                onChange={e => setConfirmarSenha(e.target.value)}
                placeholder="••••••••"
                required
                minLength={6}
              />
            </div>
            
            <div className="flex justify-end space-x-3 pt-4">
              <button
                type="button"
                onClick={handleCancel}
                className="px-4 py-2 border border-cursor-border rounded-md text-cursor-text-primary bg-white hover:bg-cursor-bg"
                disabled={loading}
              >
                Cancelar
              </button>
              <button
                type="submit"
                className="px-4 py-2 bg-cursor-primary text-white rounded-md hover:bg-cursor-primary-dark flex items-center"
                disabled={loading}
              >
                {loading ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Salvando...
                  </>
                ) : (
                  'Salvar Nova Senha'
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AlterarSenhaPage;
